+
+beforeEach(async () => {
+  clearMemoryEmbeddingProviders();
+  mocks.resolvePluginCapabilityProviders.mockReset();
+  mocks.resolvePluginCapabilityProviders.mockReturnValue([]);
+  runtimeModule = await import("./memory-embedding-provider-runtime.js");
